class Solution:
    def extract_href(self, tags: list[str]) -> list[str]:
        import re
        hrefs = []
        for tag in tags:
            href = re.search('href=['"]?([^'"]+)['"]?', tag)
            if href:
                hrefs.append(href.group(1))
            else:
                hrefs.append('')
        return hrefs
